import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../api/axios';

const STATUS_COLOR = { Pending: '#f59e0b', Approved: '#10b981', Rejected: '#ef4444' };

export default function ExpenseDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [expense, setExpense] = useState(null);

  useEffect(() => {
    api.get(`/expenses/${id}`).then((res) => setExpense(res.data));
  }, [id]);

  if (!expense) return <div style={{ padding: '2rem' }}>Loading...</div>;

  return (
    <div style={styles.page}>
      <button onClick={() => navigate(-1)} style={styles.back}>← Back</button>
      <h2>Expense Detail</h2>
      <div style={styles.card}>
        <p><strong>Employee:</strong> {expense.employee?.name} ({expense.employee?.email})</p>
        <p><strong>Category:</strong> {expense.category}</p>
        <p><strong>Amount:</strong> {expense.amount} {expense.currency}</p>
        <p><strong>Converted:</strong> {expense.convertedAmount?.toFixed(2)} {expense.convertedCurrency}</p>
        <p><strong>Date:</strong> {new Date(expense.date).toLocaleDateString()}</p>
        <p><strong>Description:</strong> {expense.description}</p>
        <p><strong>Status:</strong> <span style={{ color: STATUS_COLOR[expense.status] }}>{expense.status}</span></p>
        {expense.receiptUrl && (
          <p><strong>Receipt:</strong> <a href={`/${expense.receiptUrl}`} target="_blank" rel="noreferrer">View Receipt</a></p>
        )}
        {expense.ocrData && (
          <div>
            <strong>OCR Data:</strong>
            <pre style={{ background: '#f3f4f6', padding: '0.5rem', borderRadius: '4px' }}>
              {JSON.stringify(expense.ocrData, null, 2)}
            </pre>
          </div>
        )}
      </div>

      <h3>Approval Chain</h3>
      {expense.approvals.map((a, i) => (
        <div key={i} style={{ ...styles.step, borderLeft: `4px solid ${STATUS_COLOR[a.status]}` }}>
          <p><strong>Step {a.step}:</strong> {a.approverId?.name} ({a.approverId?.role})</p>
          <p>Status: <span style={{ color: STATUS_COLOR[a.status] }}>{a.status}</span></p>
          {a.comment && <p>Comment: {a.comment}</p>}
          {a.actionAt && <p>Acted at: {new Date(a.actionAt).toLocaleString()}</p>}
        </div>
      ))}
    </div>
  );
}

const styles = {
  page: { maxWidth: '700px', margin: '2rem auto', padding: '0 1rem' },
  card: { background: '#fff', border: '1px solid #e5e7eb', borderRadius: '8px', padding: '1.5rem', marginBottom: '1.5rem' },
  step: { background: '#fff', border: '1px solid #e5e7eb', borderRadius: '4px', padding: '1rem', marginBottom: '0.75rem' },
  back: { background: 'none', border: 'none', cursor: 'pointer', color: '#4f46e5', fontSize: '1rem', marginBottom: '1rem' },
};
